import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"黑天鹅之羽","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/4.B级/黑天鹅之羽.md","filePath":"4.资源分区/7.物品与装备/3.防具/4.B级/黑天鹅之羽.md"}'),d={name:"4.资源分区/7.物品与装备/3.防具/4.B级/黑天鹅之羽.md"};function _(l,a,p,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"黑天鹅之羽",tabindex:"-1"},[s("黑天鹅之羽 "),e("a",{class:"header-anchor",href:"#黑天鹅之羽","aria-label":'Permalink to "黑天鹅之羽"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),o('<h1 id="黑天鹅之羽-1" tabindex="-1">黑天鹅之羽 <a class="header-anchor" href="#黑天鹅之羽-1" aria-label="Permalink to &quot;黑天鹅之羽&quot;">​</a></h1><p>黑天鹅之羽<br> B+2000<br> 这套护甲由漆黑的羽毛编织而成，每一片羽毛都闪烁着幽暗的光泽，仿佛夜空中坠落的星辰。穿戴者如同化身为优雅的黑天鹅，步履间轻盈无声，羽毛在风中微微颤动，散发出神秘而危险的气息。护甲的核心镶嵌着一颗黑曜石，能够在危急时刻释放出黑暗能量，遮蔽穿戴者的身形。<br> 盔甲类型：轻甲<br> 盔甲防御 :17/17<br> 盔甲特性:【黑天鹅】【幕间】</p><p>【黑天鹅】这件护甲的盔甲防御转变为偏斜防御，你穿戴护甲时，你步态轻盈，仿佛优雅的舞者，你反射豁免提高12点，你的敏捷检定提升6点。<br> 如果你穿着这件护甲进行舞蹈或者歌唱，那么这次舞蹈或者歌唱获得6点增强加值。</p><p>【幕间】任何演员都需要一个换装期，都需要一个休息室……你在战斗中可以使用一个移动动作，直到你下回合行动前，你为自身增添11点遮蔽防御，视觉上是突然间从天而降一个独立黑纱更衣间把你自身笼罩在其中，你曼妙的身影在黑纱下若隐若现。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
